import React, { useEffect, useState } from 'react';
import Card from '@mui/material/Card';
import Typography from '@mui/material/Typography';
import { Avatar, Grid } from '@mui/material';
// import { useAuthUser, useIsAuthenticated } from 'react-auth-kit'
import { useParams } from 'react-router-dom';
// import CommentDataService from './services/comment.service'
// import { useParams } from 'react-router-dom';
import DefaultAvatar from './Default Avatar'

export default function Message({ message, conversationListItem, changeRecipient }) {

    // const auth = useAuthUser()
    const { id } = useParams()
    // const {id} = useParams()
    // const isAuthenticated = useIsAuthenticated()
    const [body, setBody] = useState('')
    const [contact, setContact] = useState('')
    // const [confirmDelete, setConfirmDelete] = useState(false)
    // const [showReply, setShowReply] = useState(false)

    conversationListItem && (
        useEffect(() => {
            if (message.to._id === id) {
                setBody(message.body)
                setContact(message.from)
            } else if (message.from._id === id) {
                setBody(`You: ${message.body}`)
                setContact(message.to)
            }
            else {
                setBody(message.body)
                setContact(message.from)
            }
        }, [message]))

    // const handleDelete = () => {
    //     deleteMessage(_id)
    // }

    const handleClick = () => {
        changeRecipient(contact)
    }

    const getAvatar = () => {
        if (contact) {
            if (contact.image.url !== '' && contact.image.url !== "/broken-image.jpg") {
                return <Avatar alt={contact.username} src={contact.image.url} />
            } else {
                return <DefaultAvatar username={contact.username} />
            }
        } else {
            if (message.from.image.url !== '' && message.from.image.url !== "/broken-image.jpg") {
                return <Avatar alt={message.from.username} src={message.from.image.url} />
            } else {
                return <DefaultAvatar username={message.from.username} />
            }
        }
    }

        //     const createReply = (obj) => {
        //         CommentDataService.reply({...obj,  commentId: _id})
        //         .then(({ data }) => {
        //             console.log(data)
        //             setReplies([...data.replies])
        //         setShowReply(false)
        //     })
        // }

        return (
            <>
                {message &&
                    <Grid width={conversationListItem ? '100%' : '80%'} marginLeft={(id === message.from._id) && 'auto'} marginRight={(id !== message.from._id) && 'auto'} >
                        <Card sx={{ width: '100%' }} onClick={conversationListItem ? handleClick : null}>
                            <Grid container item direction='row' columnGap={2} display='flex' xs={12} width='80%' padding={2} >
                                <Grid container item xs='auto' direction='column' justifyContent='center'>
                                    {getAvatar()}
                                </Grid>
                                <Grid container item xs direction='row' rowGap={2} alignItems='center'>
                                    <Grid item container direction='column' width='100%'>
                                        <Grid container item xs>

                                            <Typography variant="subtitle2" component='div' color="primary">
                                                <b>{contact.username}</b>
                                            </Typography>
                                        </Grid>

                                        <Grid container item direction='column' xs={12}>

                                            <Typography variant='body2' component='div' color="text.primary">
                                                {body !== '' ? body : message.body}
                                            </Typography>
                                        </Grid>
                                    </Grid>



                                </Grid>
                                {/* {isMessageAuthor ?
                    <Grid container item xs={1} direction='column' justifyContent='center' alignItems='flex-end' borderLeft='1px solid lightgray' width='100%' >
                        <IconButton onClick={handleDelete}>
                            <Delete fontSize='small' />
                        </IconButton>
                    </Grid>
                    : null
                } */}
                                {/* {isAuthenticated() &&
                <Grid container item xs={12} direction='row'>
                    <Button onClick={()=>setShowReply(!showReply)}>Reply</Button>
                </Grid>
}
                {showReply && 
                <Grid container item xs={10} direction='row' justifyContent='flex-end'>
                    <CommentForm createComment={createReply} />
                </Grid>
                
                
} */}
                            </Grid>
                            {/* } */}
                        </Card>
                    </Grid>
                }
            </>

        );
    }

