import { Button, Grid } from "@mui/material";
import React, { useContext } from "react";
import ResetFiltersButton from "./ResetFiltersButton";
import { ListingContext } from "./contexts/ListingContext";
import SortFilter from "./SortFilter";
import { useAuthUser, useIsAuthenticated } from 'react-auth-kit'
import ListingFormSelector from "./ListingFormSelector";

export default function FilterBar() {
    // const { model, year, trim, interior, exterior, autopilot, createSeedListing } = useContext(ListingContext)

    const { model, models, setModel, year, years, setYear, trim, trims, setTrim, interior, interiors, setInterior, exterior, exteriors, setExterior, autopilot, autopilots, setAutopilot, createSeedListing } = useContext(ListingContext)

    const auth = useAuthUser()
    const isAuthenticated = useIsAuthenticated()

    return (
        <Grid container wrap='wrap' alignItems='center' height='auto' >
            <Grid item container height='55px' wrap='nowrap' direction='row' overflow='scroll' display='flex' alignItems='center' columnGap={2}>
                {(model || year || trim || interior || exterior || autopilot) &&
                    <ResetFiltersButton />
                }
                <ListingFormSelector label='Model' data={models} value={model} setValue={setModel} isForm={false} />
                <ListingFormSelector label='Year' data={years} value={year} setValue={setYear} isForm={false} />
                <ListingFormSelector label='Trim' data={trims} value={trim} setValue={setTrim} isForm={false} />
                <ListingFormSelector label='Exterior' data={exteriors} value={exterior} setValue={setExterior} isForm={false} />
                <ListingFormSelector label='Interior' data={interiors} value={interior} setValue={setInterior} isForm={false} />
                <ListingFormSelector label='Autopilot' data={autopilots} value={autopilot} setValue={setAutopilot} isForm={false} />
                {(isAuthenticated() && auth().username === 'andrwmg') && <Button onClick={createSeedListing}>Seed</Button>}
                {/* <Button onClick={deleteAllListings}>Delete Listings</Button> */}
                {/* </Grid>
            <Grid item container marginLeft='auto'> */}
                <Grid item marginLeft='auto'>
                    <SortFilter style={{ marginLeft: 'auto' }} />
                </Grid>
            </Grid>

        </Grid>

    )
} 