import * as React from 'react';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Toolbar from '@mui/material/Toolbar';
import IconButton from '@mui/material/IconButton';
import Typography from '@mui/material/Typography';
import Menu from '@mui/material/Menu';
import MenuIcon from '@mui/icons-material/Menu';
import Container from '@mui/material/Container';
import Avatar from '@mui/material/Avatar';
import Button from '@mui/material/Button';
import Tooltip from '@mui/material/Tooltip';
import MenuItem from '@mui/material/MenuItem';
import { grey } from '@mui/material/colors';
import { useLocation, useNavigate } from 'react-router-dom';
import {useAuthUser, useIsAuthenticated} from 'react-auth-kit'
import { ListingContext } from './contexts/ListingContext';
import DefaultAvatar from './Default Avatar';

const pages = ['Listings'];

function Navbar() {
  const [anchorElNav, setAnchorElNav] = React.useState(null);
  const [anchorElUser, setAnchorElUser] = React.useState(null);
  const navigate = useNavigate()
  const location = useLocation()
  const auth = useAuthUser()
  const isAuthenticated = useIsAuthenticated()
  const [userImage, setUserImage] = React.useState("")
  const { logout, user } = React.useContext(ListingContext)

  const handleOpenNavMenu = (event) => {
    setAnchorElNav(event.currentTarget);
  };
  const handleOpenUserMenu = (event) => {
    setAnchorElUser(event.currentTarget);
  };

  const handleCloseNavMenu = () => {
    setAnchorElNav(null);
  };

  const handleCloseUserMenu = () => {
    setAnchorElUser(null);
  };

  const getBackground = () =>{
    if (location.pathname === '/'){
      return 'transparent'
    } else {
      return grey[900]
    }
  }
  

  // React.useEffect(()=>{
  //   {isAuthenticated() &&
  //   getUser()
  //   }
  //   console.log(user)
  //   console.log('getit')}, [])

    React.useEffect(()=>{
      if (auth()) {
        setUserImage(user.image.url ? user.image.url : '')
      } else
      setUserImage('')
    }, [useIsAuthenticated()])

  return (
    <AppBar position="fixed" sx={{ backgroundColor: getBackground() , color: 'white', height:'64px', boxShadow: location.pathname === '/' && 0 }}>
      <Container maxWidth="xl" style={{height: '100%'}} >
        <Toolbar disableGutters style={{height: '100%'}} >
          <Typography
            variant="h6"
            noWrap
            component="a"
            href="/"
            sx={{
              mr: 2,
              display: { xs: 'flex' },
              fontWeight: 500,
              color: 'inherit',
              textDecoration: 'none',
            }}
          >

                                Tesla Mart

                        </Typography>
          <Box sx={{ flexGrow: 1, display: { xs: 'none' } }}>
            <IconButton
              size="large"
              aria-label="account of current user"
              aria-controls="menu-appbar"
              aria-haspopup="true"
              onClick={handleOpenNavMenu}
              color="inherit"
            >
              <MenuIcon />
            </IconButton>
            <Menu
              id="menu-appbar"
              anchorEl={anchorElNav}
              anchorOrigin={{
                vertical: 'bottom',
                horizontal: 'left',
              }}
              keepMounted
              transformOrigin={{
                vertical: 'top',
                horizontal: 'left',
              }}
              open={Boolean(anchorElNav)}
              onClose={handleCloseNavMenu}
              sx={{
                display: { xs: 'none' },
              }}
            >
              {pages.map((page) => (
                <MenuItem key={page} onClick={handleCloseNavMenu}>
                  <Typography textAlign="center">{page}</Typography>
                </MenuItem>
              ))}
            </Menu>
          </Box>
          <Typography
            variant="h5"
            noWrap
            component="a"
            href="/"
            sx={{
              mr: 2,
              display: { xs: 'none' },
              flexGrow: 1,
              fontWeight: 500,
              color: 'inherit',
              textDecoration: 'none',
            }}
          >
            Tesla Mart
          </Typography>
          <Box sx={{ flexGrow: 0, marginLeft:'auto' }}>
              <Button
                key='listingsButton'
                onClick={()=>navigate('/listings')}
                sx={{ my: 2, color: 'white', display: 'block' }}
              >
                Listings
              </Button>
          </Box>

          <Box sx={{ flexGrow: 0, marginLeft: 1 }}>
          {!isAuthenticated() ?
            <Button
            key='loginButton'
            onClick={()=>navigate('/login')}
            sx={{ my: 2, color: 'white', display: 'block' }}
          >
            Log In
          </Button>
:
<>
            <Tooltip title="Open settings">
              <IconButton onClick={handleOpenUserMenu} sx={{ p: 0 }}>
              {(userImage !== '' && userImage !== "/broken-image.jpg") ?
                    <Avatar 
                      alt={user.username}
                      src={userImage}
                      />
                      :
                      <DefaultAvatar 
                      username={user.username}
                      />
          }
                {/* <Avatar alt={avatarLetter} src={userImage}/> */}
              </IconButton>
            </Tooltip>
            <Menu
              sx={{ mt: '45px' }}
              id="menu-appbar"
              anchorEl={anchorElUser}
              anchorOrigin={{
                vertical: 'top',
                horizontal: 'right',
              }}
              keepMounted
              transformOrigin={{
                vertical: 'top',
                horizontal: 'right',
              }}
              open={Boolean(anchorElUser)}
              onClose={handleCloseUserMenu}
            >
              {/* {settings.map((setting) => ( */}
              <MenuItem key='Messages' onClick={()=>navigate(`/messages/${user._id}`)}>
                  <Typography textAlign="center">Messages</Typography>
                </MenuItem>
              <MenuItem key='Profile' onClick={()=>navigate(`/profile/${user._id}`)}>
                  <Typography textAlign="center">Profile</Typography>
                </MenuItem>
                <MenuItem key='Log Out' onClick={logout}>
                  <Typography textAlign="center">Log Out</Typography>
                </MenuItem>
              {/* ))} */}
            </Menu>
            </>
            }
          </Box>
        </Toolbar>
      </Container>
    </AppBar>
  );
}
export default Navbar;