import React, { useContext, useState } from 'react';
import Button from '@mui/material/Button';
import { Grid, TextField } from '@mui/material';
import UserDataService from './services/user.service'
import { ListingContext } from './contexts/ListingContext';
import {useAuthUser} from 'react-auth-kit'

export default function MessageForm({recipient, handleClose, populateMessages, popUp}) {

    const [body, setBody] = useState('')
    const [focus, setFocus] = useState(false)
    const {setMessage, setMessageStatus, user} = useContext(ListingContext)
    const auth = useAuthUser()

    const handleBodyChange = (event) => {
        setBody(event.target.value)
    }

    const handleSubmit = async (event) => {
        event.preventDefault()
        const obj = { body: body, from: user._id, to: recipient._id }
        console.log(obj)
        setBody('')
        UserDataService.sendMessage(obj)
        .then(({data})=> {
            setMessage(data.message)
            setMessageStatus(data.messageStatus)
            !popUp && populateMessages(auth()._id, recipient._id)
        })
            handleClose()
    }

    return (
        // <Card sx={{height: 'auto', width: '100%'}} >
        //     <CardContent>
                <Grid container direction='column' width='100%'>
                <form onSubmit={handleSubmit}>
                    <Grid container item rowGap={2}>
                        {/* <Typography variant="h5" color="text.secondary">
                            Leave a comment
                        </Typography> */}
                        <TextField
                            id="outlined-body-input"
                            onFocus={() => setFocus(true)}
                            onBlur={() => setFocus(false)}
                            label="Message"
                            type="text"
                            value={body}
                            onChange={handleBodyChange}
                            autoComplete="new-body"
                            size="small"
                            fullWidth
                            required
                            multiline
                            minRows={focus || body !== '' ? 3 : 1}
                            maxRows={10}
                        />

                        <Button
                            type="submit"
                            color='primary'
                            variant='contained'
                            sx={{ width: '100%', mx: 'auto' }}>
                            Send
                        </Button>

                    </Grid>
                </form>
                </Grid>
    );
}

