import React from "react";
import Dialog from '@mui/material/Dialog';
import DialogTitle from '@mui/material/DialogTitle';
import { Grid } from "@mui/material";
import MessageForm from "./UserMessageForm";

export default function MessagePopup(props) {
    const {open, handleClose, recipient} = props

    return (
        <div>
            <Dialog open={open} onClose={handleClose} aria-labelledby='delete-dialog-title'>
                <DialogTitle id='delete-dialog-title'>Message Author</DialogTitle>
                <Grid container item padding={2}>
                <MessageForm recipient={recipient._id} handleClose={handleClose} popUp={true} />
                </Grid>
            </Dialog>
        </div>
    );
}
